function clean(value) {
  if (value === null || value === undefined) return "";
  return String(value).trim();
}

const inputItem = $json || {};
const question = clean(inputItem.input || inputItem.question || inputItem.message || "current power status at the farm");
const q = question.toLowerCase();

const asksEnergyTotal = /\b(kwh|kw\s*h|units?|unit\s+usage|cost|rand|zar|price|bill|import(ed)?|export(ed)?|total\s+(solar|pv|grid|load|usage|energy)|how much\s+(solar|pv|grid|power|electricity|energy))\b/i.test(q);
const asksRecent = /\b(last\s*24|24h|24\s*hours?|trend|history|overnight|last night|yesterday|past|previous|recent|profile|today|this morning|during the night|grid.*last|generator.*last|solar.*last|battery.*last|what happened)\b/i.test(q);

const queryType = asksRecent || asksEnergyTotal ? "recent" : "current";
const requestUrl = queryType === "recent"
  ? "https://amadeus-pig-tracking-system.onrender.com/api/telemetry/power/recent?hours=24"
  : "https://amadeus-pig-tracking-system.onrender.com/api/telemetry/power/current";

return [{
  json: {
    input: question,
    query_type: queryType,
    asks_energy_total: asksEnergyTotal,
    request_url: requestUrl,
  }
}];

function clean(value) {
  if (value === null || value === undefined) return "";
  return String(value).trim();
}

function num(value) {
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : null;
}

function fmtKw(watts) {
  const n = num(watts);
  if (n === null) return "unknown";
  return `${(n / 1000).toFixed(1)} kW`;
}

function fmtW(watts) {
  const n = num(watts);
  if (n === null) return "unknown";
  return `${Math.round(n)} W`;
}

function fmtPct(value) {
  const n = num(value);
  if (n === null) return "unknown";
  return `${Math.round(n)}%`;
}

function fmtMinutes(value) {
  const n = num(value);
  if (n === null) return "unknown";
  return `${Math.round(n)} minutes`;
}

function formatDateTime(iso) {
  if (!iso) return "unknown";
  const d = new Date(iso);
  if (Number.isNaN(d.getTime())) return iso;
  return new Intl.DateTimeFormat("en-ZA", {
    timeZone: "Africa/Johannesburg",
    year: "numeric",
    month: "short",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
    hour12: false,
  }).format(d);
}

function sentence(value) {
  return clean(value).replace(/\s+/g, " ");
}

const route = $("Code - Route Power Question").first()?.json || {};
const question = clean(route.input || "current power status at the farm");
const queryType = clean(route.query_type || "current");
const asksEnergyTotal = route.asks_energy_total === true;
const data = $json || {};
const success = data.success === true && data.status === "ok";
let answer = "";

if (!success) {
  const reason = sentence(data.message || data.error || data.summary?.headline || "The power data is not available yet.");
  answer = `I could not read the power data. ${reason}`;
} else if (queryType === "recent") {
  const window = data.window || {};
  const battery = data.battery || {};
  const power = data.power || {};
  const activity = data.activity || {};
  const summary = data.summary || {};
  const notes = Array.isArray(summary.operator_notes) ? summary.operator_notes : [];
  const lines = [];

  lines.push("Last 24h power profile (sample-based):");
  lines.push("");
  lines.push(`Data coverage: ${window.row_count ?? "unknown"}/${window.expected_samples ?? "unknown"} readings (${window.coverage_pct ?? "unknown"}%).`);
  lines.push(`Window: ${formatDateTime(window.first_reading_at)} to ${formatDateTime(window.last_reading_at)}.`);
  lines.push("");
  lines.push(`Battery: latest ${fmtPct(battery.latest_soc_pct)}, range ${fmtPct(battery.min_soc_pct)} to ${fmtPct(battery.max_soc_pct)}.`);
  lines.push(`Battery activity: charging about ${fmtMinutes(battery.charging_approx_minutes)}, discharging about ${fmtMinutes(battery.discharging_approx_minutes)}.`);
  lines.push(`Load: average ${fmtKw(power.avg_load_power_w)}, max ${fmtKw(power.max_load_power_w)}.`);
  lines.push(`Solar: average ${fmtKw(power.avg_solar_power_w)}, max ${fmtKw(power.max_solar_power_w)}.`);
  lines.push(`Grid use: about ${fmtMinutes(activity.grid_active_approx_minutes)} from ${activity.grid_active_samples ?? 0} samples.`);
  lines.push(`Generator: about ${fmtMinutes(activity.generator_active_approx_minutes)} from ${activity.generator_active_samples ?? 0} samples.`);

  if (activity.no_solar_approx_minutes !== undefined) {
    lines.push(`No-solar samples: about ${fmtMinutes(activity.no_solar_approx_minutes)}.`);
  }

  if (notes.length > 0) {
    lines.push("");
    for (const note of notes.slice(0, 4)) lines.push(`- ${sentence(note)}`);
  }

  lines.push("");
  if (asksEnergyTotal) {
    lines.push("Important: I cannot confirm kWh, cost, import, or export totals yet. This is based on 5-minute power samples, not approved energy counters.");
  } else {
    lines.push("Note: this is based on 5-minute power samples, so it is useful for trends but not confirmed kWh or cost totals yet.");
  }

  answer = lines.join("\n");
} else {
  const source = data.source || {};
  const current = data.current || {};
  const flags = data.flags || {};
  const summary = data.summary || {};
  const lines = [];
  const stale = source.is_stale === true;
  const statusWord = stale ? "latest available" : "current";
  const headline = sentence(summary.headline || "Power state is available.");

  lines.push(`Power status (${statusWord}): ${headline}`);
  lines.push("");
  lines.push(`Battery: ${fmtPct(current.battery_soc_pct)} (${sentence(current.battery_state || "state unknown")})`);
  lines.push(`Solar: ${fmtKw(current.solar_power_w)} (PV1 ${fmtW(current.pv1_power_w)}, PV2 ${fmtW(current.pv2_power_w)})`);
  lines.push(`Load: ${fmtKw(current.load_power_w)}`);
  lines.push(`Grid: ${sentence(current.grid_state || "unknown")} (${fmtW(current.grid_power_w)})`);
  lines.push(`Generator: ${sentence(current.generator_state || "unknown")} (${fmtW(current.generator_power_w)})`);
  lines.push("");
  lines.push(`Latest reading: ${formatDateTime(source.last_reading_at)} (${source.data_age_minutes ?? "unknown"} minutes old).`);

  if (stale) lines.push("Warning: this reading is stale, so treat it as the last known state rather than live power status.");
  if (flags.low_battery === true) lines.push("Warning: battery is low.");
  if (flags.high_load === true) lines.push("Warning: load is high.");
  if (flags.no_solar === true) lines.push("Note: no solar production is showing right now.");

  answer = lines.join("\n");
}

return [{
  json: {
    success,
    input: question,
    query_type: queryType,
    asks_energy_total: asksEnergyTotal,
    answer,
    output: answer,
    sunsynk_response: answer,
    telemetry_source: queryType === "recent" ? "backend_supabase_recent_power" : "backend_supabase_current_power",
    backend_payload: data,
  }
}];

